'use client';

import React, { useEffect, useState } from 'react';
import {
  Box,
  Container,
  Typography,
  Paper,
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  Chip,
  CircularProgress,
  Stack,
} from '@mui/material';
import dayjs from 'dayjs';

type Order = {
  _id: string;
  orderId: string;
  customerName?: string;
  companyName?: string;
  note?: string;
  category: string;
  total: number;
  discount?: number;
  payment: 'cash' | 'promptpay';
  status: 'pending' | 'paid' | 'cancelled';
  createdAt: string;
};

export default function OrdersPage() {
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const base = process.env.NEXT_PUBLIC_API_URL ?? '';
    if (!base) return;

    fetch(`${base}/orders`)
      .then(async res => {
        if (!res.ok) throw new Error('โหลดข้อมูลล้มเหลว');
        return res.json();
      })
      .then(data => {
        setOrders(data);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, []);

  const statusColor = (status: string) => {
    switch (status) {
      case 'paid':
        return 'success';
      case 'pending':
        return 'warning';
      case 'cancelled':
        return 'error';
      default:
        return 'default';
    }
  };

  return (
    <Container maxWidth="lg" sx={{ py: 3 }}>
      <Typography variant="h5" fontWeight={800} mb={2}>
        📋 รายการออเดอร์
      </Typography>

      <Paper sx={{ width: '100%', overflow: 'hidden' }}>
        {loading ? (
          <Box textAlign="center" py={5}>
            <CircularProgress />
            <Typography mt={2}>กำลังโหลดข้อมูล...</Typography>
          </Box>
        ) : (
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Order ID</TableCell>
                <TableCell>ชื่อลูกค้า</TableCell>
                <TableCell>บริษัท</TableCell>
                <TableCell>หมวด</TableCell>
                <TableCell>ยอดรวม</TableCell>
                <TableCell>การชำระเงิน</TableCell>
                <TableCell>สถานะ</TableCell>
                <TableCell>วันที่สร้าง</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {orders.length === 0 && (
                <TableRow>
                  <TableCell colSpan={8} align="center" sx={{ py: 4 }}>
                    <Typography color="text.secondary">
                      ❌ ยังไม่มีออเดอร์
                    </Typography>
                  </TableCell>
                </TableRow>
              )}
              {orders.map(order => (
                <TableRow key={order._id}>
                  <TableCell>{order.orderId}</TableCell>
                  <TableCell>{order.customerName || '-'}</TableCell>
                  <TableCell>{order.companyName || '-'}</TableCell>
                  <TableCell>{order.category}</TableCell>
                  <TableCell>
                    ฿{order.total.toLocaleString('th-TH')}
                  </TableCell>
                  <TableCell>
                    {order.payment === 'cash' ? '💵 เงินสด' : '📱 PromptPay'}
                  </TableCell>
                  <TableCell>
                    <Chip
                      size="small"
                      label={order.status}
                      color={statusColor(order.status) as any}
                    />
                  </TableCell>
                  <TableCell>
                    {dayjs(order.createdAt).format('DD/MM/YYYY HH:mm')}
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}
      </Paper>
    </Container>
  );
}
